  1→import { useRef, useCallback, useEffect, useState, useMemo } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { useProject } from '@/app/ProjectProvider';
  4→import { usePlanClipboardController } from '@/clipboard/usePlanClipboardController';
  5→import { normalizeRectBounds } from '@/clipboard/planClipboard';
  6→import { getFloorElevation } from '@/domain/floorModels';
  7→import { resolveRoofSectionCut } from '@/domain/roofModels';
  8→import { filterProjectByPhase } from '@/domain/phaseFilter';
  9→import { buildProjectSectionScene } from '@/sections/scene';
 10→import { getSectionVisibilityMessage, SECTION_VISIBILITY_REASONS } from '@/sections/diagnostics';
 11→import { usePhaseFilteredFloor } from '@/hooks/usePhaseFilteredFloor';
 12→import { useEditorTool } from '@/editor/useEditorTool';
 13→import { MIN_ZOOM, MAX_ZOOM, ZOOM_FACTOR } from '@/domain/defaults';
 14→import { formatSurveyorBearing, pointsToSurveyorBearing } from '@/geometry/bearing';
 15→import { TOOLS } from '@/editor/tools';
 16→import ClipboardPreviewLayer from './ClipboardPreviewLayer';
 17→import CompassOverlay from '@/ui/CompassOverlay';
 18→import GridRenderer from './GridRenderer';
 19→import SlabRenderer from './SlabRenderer';
 20→import WallRenderer from './WallRenderer';
 21→import BeamRenderer from './BeamRenderer';
 22→import StairRenderer from './StairRenderer';
 23→import DoorRenderer from './DoorRenderer';
 24→import WindowRenderer from './WindowRenderer';
 25→import RoomRenderer from './RoomRenderer';
 26→import AnnotationRenderer from './AnnotationRenderer';
 27→import ElevationRenderer from './ElevationRenderer';
 28→import SectionRenderer from './SectionRenderer';
 29→import SelectionOverlay from './SelectionOverlay';
 30→import DimensionPreview from './DimensionPreview';
 31→import WallPreview from './WallPreview';
 32→import LandingRenderer from './LandingRenderer';
 33→import LandingPreview from './LandingPreview';
 34→import ColumnRenderer from './ColumnRenderer';
 35→import ColumnPreview from './ColumnPreview';
 36→import FixtureDefs from './FixtureDefs';
 37→import FixtureRenderer from './FixtureRenderer';
 38→import FixturePreview from './FixturePreview';
 39→import BeamPreview from './BeamPreview';
 40→import StairPreview from './StairPreview';
 41→import SlabPreview from './SlabPreview';
 42→import DoorWindowPreview from './DoorWindowPreview';
 43→import RoomPreview from './RoomPreview';
 44→import SectionCutRenderer from './SectionCutRenderer';
 45→import SectionCutPreview from './SectionCutPreview';
 46→import RailingRenderer from './RailingRenderer';
 47→import RailingPreview from './RailingPreview';
 48→import RegionSelectionOverlay from './RegionSelectionOverlay';
 49→import RoofRenderer from './RoofRenderer';
 50→import RoofElevationRenderer from './RoofElevationRenderer';
 51→import RoofSectionRenderer from './RoofSectionRenderer';
 52→import RoofSelectionOverlay from './RoofSelectionOverlay';
 53→import RoofPreviewLayer from './RoofPreviewLayer';
 54→import TrussRenderer from './TrussRenderer';
 55→import TrussSelectionOverlay from './TrussSelectionOverlay';
 56→import TrussDrawOverlay from './TrussDrawOverlay';
 57→import TrussDetailRenderer from './TrussDetailRenderer';
 58→import TrussSectionRenderer from './TrussSectionRenderer';
 59→import { CenterViewIcon, ExpandIcon, CollapseIcon } from '@/ui/ToolbarIcons';
 60→import { isTypingTarget } from '@/utils/keyboard';
 61→import styles from './SvgCanvas.module.css';
 62→
 63→function screenToModel(screenX, screenY, viewport, svgRect) {
 64→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 65→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 66→  return { x, y };
 67→}
 68→
 69→export default function SvgCanvas() {
 70→  const svgRef = useRef(null);
 71→  const isPanning = useRef(false);
 72→  const lastPanPos = useRef({ x: 0, y: 0 });
 73→  const spaceHeld = useRef(false);
 74→  const cursorPosRef = useRef({ x: 0, y: 0 });
 75→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 76→
 77→  const { project, dispatch, getFloor } = useProject();
 78→  const editor = useEditor();
 79→  const {
 80→    activeTool, selectedId, selectedType, toolState,
 81→    viewport, showGrid, snapEnabled, activeFloorId, statusMessage, viewMode, activeSectionCutId,
 82→    regionSelection, pastePreview, maximizedPanel,
 83→    modelTarget,
 84→    activePhaseId, phaseViewMode,
 85→    dispatch: editorDispatch,
 86→  } = editor;
 87→
 88→  const floor = getFloor(activeFloorId);
 89→  const filteredFloor = usePhaseFilteredFloor(floor, project, activePhaseId, phaseViewMode);
 90→  const filteredProject = useMemo(
 91→    () => filterProjectByPhase(project, activePhaseId, phaseViewMode),
 92→    [project, activePhaseId, phaseViewMode]
 93→  );
 94→  const roofSystem = filteredProject.roofSystem || null;
 95→  const roofHiddenByPhase = Boolean(project.roofSystem && !roofSystem);
 96→  const hasProjectRoof = Boolean(project.roofSystem);
 97→  const hasProjectRailings = Boolean((project.floors || []).some((entry) => (entry.railings || []).length));
 98→  const visibleProjectRailings = Boolean((filteredProject.floors || []).some((entry) => (entry.railings || []).length));
 99→  const railingsHiddenByPhase = Boolean(hasProjectRailings && !visibleProjectRailings);
100→  const hasProjectTrusses = Boolean((filteredProject.trussSystems || []).length);
101→  const floorTrussSystems = (filteredProject.trussSystems || []).filter((trussSystem) => trussSystem.floorId === activeFloorId);
102→  const allFloorTrussSystems = (project.trussSystems || []).filter((trussSystem) => trussSystem.floorId === activeFloorId);
103→  const trussesHiddenByPhase = Boolean(allFloorTrussSystems.length && !floorTrussSystems.length);
104→  const activeTrussContext = useMemo(() => {
105→    if (selectedType === 'trussSystem') {
106→      const trussSystem = (filteredProject.trussSystems || []).find((entry) => entry.id === selectedId) || null;
107→      return {
108→        trussSystem,
109→        trussInstanceId: null,
110→      };
111→    }
112→    if (selectedType === 'trussInstance') {
113→      const trussSystem = (filteredProject.trussSystems || []).find((entry) => (
114→        (entry.trussInstances || []).some((trussInstance) => trussInstance.id === selectedId)
115→      )) || null;
116→      return {
117→        trussSystem,
118→        trussInstanceId: selectedId,
119→      };
120→    }
121→    return {
122→      trussSystem: floorTrussSystems[0] || null,
123→      trussInstanceId: floorTrussSystems[0]?.trussInstances?.[0]?.id || null,
124→    };
125→  }, [filteredProject.trussSystems, floorTrussSystems, selectedId, selectedType]);
126→  const {
127→    copySelection,
128→    cutSelection,
129→    beginPaste,
130→    updatePastePreview,
131→    cancelPaste,
132→    placePaste,
133→    previewContent,
134→  } = usePlanClipboardController();
135→
136→  const tool = useEditorTool({
137→    activeTool,
138→    dispatch,
139→    editorDispatch,
140→    project,
141→    getFloor,
142→    activeFloorId,
143→    roofSystem,
144→    trussSystems: floorTrussSystems,
145→    modelTarget,
146→    viewport,
147→    snapEnabled,
148→    selectedId,
149→    selectedType,
150→    toolState,
151→    viewMode,
152→    activePhaseId,
153→  });
154→
155→  const getModelPos = useCallback((e) => {
156→    const rect = svgRef.current.getBoundingClientRect();
157→    return screenToModel(e.clientX, e.clientY, viewport, rect);
158→  }, [viewport]);
159→
160→  const handleMouseDown = useCallback((e) => {
161→    // Middle mouse or space+left for pan
162→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
163→      isPanning.current = true;
164→      lastPanPos.current = { x: e.clientX, y: e.clientY };
165→      e.preventDefault();
166→      return;
167→    }
168→
169→    const modelPos = getModelPos(e);
170→    if (modelTarget === 'floor' && pastePreview?.active && e.button === 0) {
171→      placePaste(modelPos);
172→      return;
173→    }
174→    tool.onMouseDown(modelPos, e);
175→  }, [getModelPos, modelTarget, pastePreview, placePaste, tool]);
176→
177→  const handleMouseMove = useCallback((e) => {
178→    if (isPanning.current) {
179→      const dx = e.clientX - lastPanPos.current.x;
180→      const dy = e.clientY - lastPanPos.current.y;
181→      editorDispatch({ type: 'PAN', dx, dy });
182→      lastPanPos.current = { x: e.clientX, y: e.clientY };
183→      return;
184→    }
185→
186→    const modelPos = getModelPos(e);
187→    cursorPosRef.current = modelPos;
188→    setCursorPos(modelPos);
189→    if (modelTarget === 'floor' && pastePreview?.active) {
190→      updatePastePreview(modelPos);
191→      return;
192→    }
193→    tool.onMouseMove(modelPos, e);
194→  }, [getModelPos, modelTarget, pastePreview, tool, updatePastePreview, editorDispatch]);
195→
196→  const handleMouseUp = useCallback((e) => {
197→    if (isPanning.current) {
198→      isPanning.current = false;
199→      return;
200→    }
201→    if (modelTarget === 'floor' && pastePreview?.active) return;
202→    const modelPos = getModelPos(e);
203→    tool.onMouseUp(modelPos, e);
204→  }, [getModelPos, modelTarget, pastePreview, tool]);
205→
206→  const handleDoubleClick = useCallback((e) => {
207→    if (modelTarget === 'floor' && pastePreview?.active) return;
208→    const modelPos = getModelPos(e);
209→    tool.onDoubleClick(modelPos, e);
210→  }, [getModelPos, modelTarget, pastePreview, tool]);
211→
212→  const handleWheel = useCallback((e) => {
213→    e.preventDefault();
214→    const rect = svgRef.current.getBoundingClientRect();
215→    const mouseX = e.clientX - rect.left;
216→    const mouseY = e.clientY - rect.top;
217→
218→    const direction = e.deltaY < 0 ? 1 : -1;
219→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
220→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
221→
222→    // Zoom centered on cursor
223→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
224→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
225→
226→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
227→  }, [viewport, editorDispatch]);
228→
229→  const handleResetCenterPoint = useCallback(() => {
230→    const rect = svgRef.current?.getBoundingClientRect();
231→    if (!rect) return;
232→
233→    editorDispatch({
234→      type: 'SET_VIEWPORT',
235→      viewport: {
236→        ...viewport,
237→        panX: rect.width / 2,
238→        panY: rect.height / 2,
239→      },
240→    });
241→  }, [editorDispatch, viewport]);
242→
243→  useEffect(() => {
244→    if (!statusMessage) return undefined;
245→
246→    const timer = window.setTimeout(() => {
247→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
248→    }, 2500);
249→
250→    return () => window.clearTimeout(timer);
251→  }, [statusMessage, editorDispatch]);
252→
253→  useEffect(() => {
254→    const handleKeyDown = (e) => {
255→      if (isTypingTarget(e.target)) return;
256→
257→      if (e.key === ' ') {
258→        spaceHeld.current = true;
259→        e.preventDefault();
260→      }
261→
262→      if ((e.ctrlKey || e.metaKey) && viewMode === 'plan' && modelTarget === 'floor') {
263→        const key = e.key.toLowerCase();
264→        if (key === 'c') {
265→          e.preventDefault();
266→          copySelection();
267→          return;
268→        }
269→        if (key === 'x') {
270→          e.preventDefault();
271→          cutSelection();
272→          return;
273→        }
274→        if (key === 'v') {
275→          e.preventDefault();
276→          beginPaste(cursorPosRef.current);
277→          return;
278→        }
279→      }
280→
281→      if (e.key === 'Escape' && modelTarget === 'floor' && pastePreview?.active) {
282→        e.preventDefault();
283→        cancelPaste();
284→        return;
285→      }
286→
287→      // Tool shortcuts
288→      if (viewMode === 'plan' && !e.ctrlKey && !e.metaKey) {
289→        if (modelTarget === 'roof') {
290→          switch (e.key.toLowerCase()) {
291→            case 'v':
292→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
293→              return;
294→            case 'p':
295→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOF_PARAPET });
296→              return;
297→            case 'g':
298→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOF_DRAIN });
299→              return;
300→            case 'o':
301→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOF_OPENING });
302→              return;
303→          }
304→        } else if (modelTarget === 'truss') {
305→          switch (e.key.toLowerCase()) {
306→            case 'v':
307→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
308→              return;
309→            case 't': {
310→              const targetTrussSystem = selectedType === 'trussSystem'
311→                ? floorTrussSystems.find((entry) => entry.id === selectedId) || null
312→                : selectedType === 'trussInstance'
313→                  ? floorTrussSystems.find((entry) => (
314→                      (entry.trussInstances || []).some((trussInstance) => trussInstance.id === selectedId)
315→                    )) || null
316→                  : null;
317→              const selectedTrussInstance = selectedType === 'trussInstance' && targetTrussSystem
318→                ? (targetTrussSystem.trussInstances || []).find((entry) => entry.id === selectedId) || null
319→                : null;
320→              const lastSystemInstance = targetTrussSystem && (targetTrussSystem.trussInstances || []).length
321→                ? targetTrussSystem.trussInstances[targetTrussSystem.trussInstances.length - 1]
322→                : null;
323→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.TRUSS_DRAW });
324→              editorDispatch({
325→                type: 'UPDATE_TOOL_STATE',
326→                payload: {
327→                  targetTrussSystemId: targetTrussSystem?.id || null,
328→                  trussTypeId: selectedTrussInstance?.trussTypeId
329→                    || lastSystemInstance?.trussTypeId
330→                    || null,
331→                  trussMaterial: selectedTrussInstance?.material
332→                    || lastSystemInstance?.material
333→                    || null,
334→                },
335→              });
336→              return;
337→            }
338→          }
339→        } else {
340→          switch (e.key.toLowerCase()) {
341→            case 'v':
342→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
343→              return;
344→            case 'm':
345→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DIMENSION });
346→              return;
347→            case 'w':
348→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WALL });
349→              return;
350→            case 'b':
351→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.BEAM });
352→              return;
353→            case 't':
354→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.STAIR });
355→              return;
356→            case 'q':
357→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SECTION });
358→              return;
359→            case 's':
360→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
361→              return;
362→            case 'r':
363→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
364→              return;
365→            case 'd':
366→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
367→              return;
368→            case 'n':
369→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
370→              return;
371→            case 'c':
372→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
373→              return;
374→            case 'l':
375→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.LANDING });
376→              return;
377→            case 'h':
378→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.RAILING });
379→              return;
380→            case 'f':
381→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.FIXTURE });
382→              editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType: 'kitchenTop', previewRotation: 0 } });
383→              return;
384→          }
385→        }
386→      }
387→
388→      tool.onKeyDown(e);
389→    };
390→
391→    const handleKeyUp = (e) => {
392→      if (isTypingTarget(e.target)) return;
393→
394→      if (e.key === ' ') {
395→        spaceHeld.current = false;
396→      }
397→    };
398→
399→    window.addEventListener('keydown', handleKeyDown);
400→    window.addEventListener('keyup', handleKeyUp);
401→    return () => {
402→      window.removeEventListener('keydown', handleKeyDown);
403→      window.removeEventListener('keyup', handleKeyUp);
404→    };
405→  }, [beginPaste, cancelPaste, copySelection, cutSelection, modelTarget, pastePreview?.active, tool, editorDispatch, viewMode, selectedId, selectedType, floorTrussSystems]);
406→
407→  // Prevent default context menu on SVG
408→  useEffect(() => {
409→    const svg = svgRef.current;
410→    if (!svg) return;
411→    const prevent = (e) => e.preventDefault();
412→    svg.addEventListener('contextmenu', prevent);
413→    svg.addEventListener('wheel', handleWheel, { passive: false });
414→    return () => {
415→      svg.removeEventListener('contextmenu', prevent);
416→      svg.removeEventListener('wheel', handleWheel);
417→    };
418→  }, [handleWheel]);
419→
420→  const cursor = spaceHeld.current ? 'grab' : (modelTarget === 'floor' && pastePreview?.active) ? 'copy' : tool.getCursor();
421→  const zoomPercent = Math.round(viewport.zoom * 1000);
422→  const displayedTool = viewMode.startsWith('elevation_') ? 'select' : activeTool;
423→  const isCanvasMaximized = maximizedPanel === 'canvas';
424→  const marqueeBounds = toolState.dragType === 'marquee' && toolState.startPos && toolState.currentPos
425→    ? normalizeRectBounds(toolState.startPos, toolState.currentPos)
426→    : null;
427→  const selectionCount = regionSelection?.objectCount || 0;
428→  const liveWallBearing = modelTarget === 'floor' && activeTool === TOOLS.WALL && toolState.start && toolState.preview
429→    ? formatSurveyorBearing(pointsToSurveyorBearing(toolState.start, toolState.preview))
430→    : null;
431→  const hasRoofSectionCut = Boolean(resolveRoofSectionCut(project, activeFloorId, activeSectionCutId).sectionCut);
432→  const hasTrussSectionCut = Boolean((floor?.sectionCuts || []).length);
433→  const roofSectionScene = useMemo(() => {
434→    if (modelTarget !== 'roof' || viewMode !== 'section_view') return null;
435→    const { floor: roofFloor, sectionCut } = resolveRoofSectionCut(project, activeFloorId, activeSectionCutId);
436→    if (!roofFloor || !sectionCut) return null;
437→    return buildProjectSectionScene(filteredProject, roofFloor.id, sectionCut.id);
438→  }, [activeFloorId, activeSectionCutId, filteredProject, modelTarget, project, viewMode]);
439→  const roofSectionReason = roofHiddenByPhase
440→    ? SECTION_VISIBILITY_REASONS.HIDDEN_BY_PHASE
441→    : roofSectionScene?.diagnostics?.roof?.reason || null;
442→  const roofSectionMessage = getSectionVisibilityMessage('roof', roofSectionReason);
443→  const trussSectionScene = useMemo(() => {
444→    if (modelTarget !== 'truss' || viewMode !== 'section_view' || !filteredFloor) return null;
445→    const cuts = filteredFloor.sectionCuts || [];
446→    const sectionCut = (activeSectionCutId && cuts.find((entry) => entry.id === activeSectionCutId)) || cuts[0] || null;
447→    if (!sectionCut) return null;
448→    return buildProjectSectionScene(filteredProject, filteredFloor.id, sectionCut.id);
449→  }, [activeSectionCutId, filteredFloor, filteredProject, modelTarget, viewMode]);
450→  const trussSectionMessage = getSectionVisibilityMessage('truss', trussSectionScene?.diagnostics?.truss?.reason || null);
451→  const floorSectionScene = useMemo(() => {
452→    if (modelTarget !== 'floor' || viewMode !== 'section_view' || !filteredFloor) return null;
453→    const cuts = filteredFloor.sectionCuts || [];
454→    const sectionCut = (activeSectionCutId && cuts.find((entry) => entry.id === activeSectionCutId)) || cuts[0] || null;
455→    if (!sectionCut) return null;
456→    return buildProjectSectionScene(filteredProject, filteredFloor.id, sectionCut.id);
457→  }, [activeSectionCutId, filteredFloor, filteredProject, modelTarget, viewMode]);
458→  const floorRoofSectionReason = roofHiddenByPhase
459→    ? SECTION_VISIBILITY_REASONS.HIDDEN_BY_PHASE
460→    : floorSectionScene?.diagnostics?.roof?.reason || null;
461→  const floorRoofSectionMessage = (hasProjectRoof || roofHiddenByPhase)
462→    ? getSectionVisibilityMessage('roof', floorRoofSectionReason)
463→    : null;
464→  const floorRailingSectionReason = railingsHiddenByPhase
465→    ? SECTION_VISIBILITY_REASONS.HIDDEN_BY_PHASE
466→    : floorSectionScene?.diagnostics?.railing?.reason || null;
467→  const floorRailingSectionMessage = (hasProjectRailings || railingsHiddenByPhase)
468→    ? getSectionVisibilityMessage('railing', floorRailingSectionReason)
469→    : null;
470→
471→  return (
472→    <div className={styles.canvasContainer}>
473→      <CompassOverlay className={styles.compassDock} />
474→      <svg
475→        ref={svgRef}
476→        className={styles.svg}
477→        style={{ cursor }}
478→        onPointerDown={handleMouseDown}
479→        onPointerMove={handleMouseMove}
480→        onPointerUp={handleMouseUp}
481→        onDoubleClick={handleDoubleClick}
482→      >
483→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
484→          {viewMode === 'plan' && showGrid && <GridRenderer />}
485→          {viewMode === 'plan' && showGrid && (
486→            <rect
487→              x={-100000} y={-100000}
488→              width={200000} height={200000}
489→              fill="url(#grid-major)"
490→              style={{ pointerEvents: 'none' }}
491→            />
492→          )}
493→          {modelTarget === 'roof' ? (
494→            roofSystem || (viewMode === 'section_view' && roofHiddenByPhase) ? (
495→              <>
496→                {viewMode === 'plan' ? (
497→                  roofSystem ? (
498→                    <>
499→                      <RoofRenderer roofSystem={roofSystem} selectedId={selectedId} selectedType={selectedType} />
500→                      <RoofSelectionOverlay
501→                        roofSystem={roofSystem}
502→                        selectedId={selectedId}
503→                        selectedType={selectedType}
504→                        zoom={viewport.zoom}
505→                      />
506→                      <RoofPreviewLayer activeTool={activeTool} toolState={toolState} roofSystem={roofSystem} />
507→                    </>
508→                  ) : (
509→                    <g className="roof-empty-view">
510→                      <text
511→                        x={0}
512→                        y={0}
513→                        textAnchor="middle"
514→                        dominantBaseline="middle"
515→                        fill="var(--color-text-secondary)"
516→                        fontSize={180}
517→                        fontFamily="var(--font-blueprint)"
518→                      >
519→                        Roof is hidden in the current phase view.
520→                      </text>
521→                    </g>
522→                  )
523→                ) : viewMode === 'section_view' ? (
524→                  <RoofSectionRenderer
525→                    project={filteredProject}
526→                    preferredFloorId={activeFloorId}
527→                    activeSectionCutId={activeSectionCutId}
528→                    roofHiddenByPhase={roofHiddenByPhase}
529→                  />
530→                ) : viewMode.startsWith('elevation_') ? (
531→                  roofSystem ? (
532→                    <RoofElevationRenderer
533→                      roofSystem={roofSystem}
534→                      viewMode={viewMode}
535→                      selectedId={selectedId}
536→                      selectedType={selectedType}
537→                    />
538→                  ) : (
539→                    <g className="roof-empty-view">
540→                      <text
541→                        x={0}
542→                        y={0}
543→                        textAnchor="middle"
544→                        dominantBaseline="middle"
545→                        fill="var(--color-text-secondary)"
546→                        fontSize={180}
547→                        fontFamily="var(--font-blueprint)"
548→                      >
549→                        Roof is hidden in the current phase view.
550→                      </text>
551→                    </g>
552→                  )
553→                ) : (
554→                  <g className="roof-empty-view">
555→                    <text
556→                      x={0}
557→                      y={0}
558→                      textAnchor="middle"
559→                      dominantBaseline="middle"
560→                      fill="var(--color-text-secondary)"
561→                      fontSize={180}
562→                      fontFamily="var(--font-blueprint)"
563→                    >
