 88→function buildContentTransform(viewport, source, contentRect) {
 89→  const bounds = source.bounds || { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
 90→  const sourceWidth = Math.max(1, bounds.maxX - bounds.minX);
 91→  const sourceHeight = Math.max(1, bounds.maxY - bounds.minY);
 92→  const scale = sourceFitsFrame(source)
 93→    ? Math.min(contentRect.width / sourceWidth, contentRect.height / sourceHeight)
 94→    : (1 / resolveViewportScale(viewport));
 95→
 96→  const drawnWidth = sourceWidth * scale;
 97→  const drawnHeight = sourceHeight * scale;
 98→  const translateX = (contentRect.width - drawnWidth) / 2 - bounds.minX * scale;
 99→  const translateY = (contentRect.height - drawnHeight) / 2 - bounds.minY * scale;
100→
101→  return {
102→    scale,
103→    translateX,
104→    translateY,
105→  };
106→}
