108→function buildViewportScene(viewport, source, sheet, rect) {
109→  const frameRect = snapRectToGrid(rect);
110→  const contentRect = {
111→    x: frameRect.x + SHEET_TOKENS.viewportPadding,
112→    y: frameRect.y + SHEET_TOKENS.viewportPadding,
113→    width: Math.max(10, frameRect.width - SHEET_TOKENS.viewportPadding * 2),
114→    height: Math.max(10, frameRect.height - SHEET_TOKENS.viewportPadding * 2),
115→  };
116→
117→  const captionGap = SHEET_TOKENS.viewportCaptionGap;
118→  const captionHeight = SHEET_TOKENS.viewportCaptionHeight;
119→  const captionY = viewport.captionPosition === 'above'
120→    ? frameRect.y - captionGap
121→    : frameRect.y + frameRect.height + captionGap + captionHeight;
122→
123→  const caption = {
124→    position: viewport.captionPosition || 'below',
125→    x: frameRect.x,
126→    y: captionY,
127→    width: frameRect.width,
128→    primaryText: resolveViewportTitle(viewport, source),
129→    secondaryText: formatCaptionSecondary(viewport, source, sheet),
130→  };
131→
132→  return {
133→    ...viewport,
134→    x: frameRect.x,
135→    y: frameRect.y,
136→    width: frameRect.width,
137→    height: frameRect.height,
138→    title: caption.primaryText,
139→    source,
140→    frameRect,
141→    clipRect: contentRect,
142→    contentRect,
143→    caption,
144→    contentTransform: buildContentTransform(viewport, source, contentRect),
145→    autoLayoutApplied: !viewport.lockAutoLayout,
146→  };
147→}
