429→export function fitViewportToSheet(viewport, sheet) {
430→  const paper = getPaperPreset(sheet.paperSize);
431→  const zones = buildSheetZones(paper);
432→  const captionClearance = getCaptionClearance(viewport);
433→  const captionAbove = viewport.captionPosition === 'above' ? captionClearance : 0;
434→  const captionBelow = viewport.captionPosition === 'below' ? captionClearance : 0;
435→  const width = clamp(
436→    viewport.width,
437→    SHEET_TOKENS.viewportMinWidth,
438→    zones.contentArea.width
439→  );
440→  const height = clamp(
441→    viewport.height,
442→    SHEET_TOKENS.viewportMinHeight,
443→    zones.contentArea.height - captionClearance
444→  );
445→  const maxX = zones.contentArea.x + zones.contentArea.width - width;
446→  const minY = zones.contentArea.y + captionAbove;
447→  const maxY = zones.contentArea.y + zones.contentArea.height - height - captionBelow;
448→
449→  return {
450→    ...viewport,
451→    ...snapRectToGrid({
452→      x: clamp(viewport.x, zones.contentArea.x, maxX),
453→      y: clamp(viewport.y, minY, Math.max(minY, maxY)),
454→      width,
455→      height,
456→    }),
457→  };
458→}
