190→            x={tag.position.x}
191→            dy={index === 0 ? 0 : lineHeight}
192→            fontSize={isRoom && index > 0 ? areaSize : nameSize}
193→            fill={isRoom && index > 0 ? DRAWING_GRAPHICS.annotation.textMuted : undefined}
194→            fontWeight={isRoom && index > 0 ? 500 : undefined}
195→          >
196→            {line}
197→          </tspan>
198→        ))}
199→      </text>
200→    </g>
201→  );
202→}
