  1→import * as THREE from 'three';
  2→
  3→const SELECTED_SURFACE_COLOR = new THREE.Color(0xcdeedd);
  4→const SELECTED_EMISSIVE_COLOR = new THREE.Color(0x0f8f74);
  5→const SELECTED_OUTLINE_COLOR = new THREE.Color(0x0f8f74);
  6→
  7→function planPointToWorld(point, elevation = 0) {
  8→  return new THREE.Vector3(point.x, elevation, point.y);
  9→}
 10→
 11→function planAngleToWorldRotation(angle = 0) {
 12→  return -angle;
 13→}
 14→
 15→function createShape(outline, holes = []) {
 16→  const shape = new THREE.Shape();
 17→  outline.forEach((point, index) => {
 18→    if (index === 0) {
 19→      // Flip plan Y here so the rotated extrusion preserves the blueprint's handedness.
 20→      shape.moveTo(point.x, -point.y);
 21→      return;
 22→    }
 23→    shape.lineTo(point.x, -point.y);
 24→  });
 25→  shape.closePath();
 26→
 27→  holes.forEach((hole) => {
 28→    if (!hole?.length) return;
 29→    const path = new THREE.Path();
 30→    hole.forEach((point, index) => {
 31→      if (index === 0) {
 32→        path.moveTo(point.x, -point.y);
 33→        return;
 34→      }
 35→      path.lineTo(point.x, -point.y);
 36→    });
 37→    path.closePath();
 38→    shape.holes.push(path);
 39→  });
 40→
 41→  return shape;
 42→}
 43→
 44→function applySelectedSurfaceStyle(material) {
 45→  if (material.color) {
 46→    material.color.lerp(SELECTED_SURFACE_COLOR, 0.36);
 47→  }
 48→  if ('emissive' in material && material.emissive) {
 49→    material.emissive.copy(SELECTED_EMISSIVE_COLOR);
 50→    material.emissiveIntensity = material.transparent ? 0.12 : 0.22;
 51→  }
 52→  if (material.transparent) {
 53→    material.opacity = Math.min(0.82, Math.max(material.opacity ?? 1, 0.58));
 54→  }
 55→}
 56→
 57→function createMeshMaterial(materialPalette, materialKey, isSelected) {
 58→  const material = materialPalette[materialKey].clone();
 59→  if (isSelected) applySelectedSurfaceStyle(material);
 60→  return material;
 61→}
 62→
 63→function createOutlineMaterial(materialPalette, isSelected) {
 64→  const material = materialPalette.outline.clone();
 65→  if (isSelected) {
 66→    material.color.copy(SELECTED_OUTLINE_COLOR);
 67→    material.opacity = 1;
 68→  }
 69→  return material;
 70→}
 71→
 72→function addOutline(object3d, materialPalette, isSelected) {
 73→  if (!object3d.geometry) return;
 74→  const edges = new THREE.EdgesGeometry(object3d.geometry, 20);
 75→  const outline = new THREE.LineSegments(edges, createOutlineMaterial(materialPalette, isSelected));
 76→  object3d.add(outline);
 77→}
 78→
 79→function createPrismObject(descriptor, materialPalette, isSelected) {
 80→  const geometry = new THREE.ExtrudeGeometry(createShape(descriptor.outline, descriptor.holes), {
 81→    depth: descriptor.height,
 82→    bevelEnabled: false,
 83→    curveSegments: 1,
 84→    steps: 1,
 85→  });
 86→
 87→  geometry.rotateX(-Math.PI / 2);
 88→  geometry.translate(0, descriptor.baseElevation, 0);
 89→
 90→  const mesh = new THREE.Mesh(geometry, createMeshMaterial(materialPalette, descriptor.materialKey, isSelected));
 91→  mesh.castShadow = true;
 92→  mesh.receiveShadow = true;
 93→  addOutline(mesh, materialPalette, isSelected);
 94→  return mesh;
 95→}
 96→
 97→function createRoofMeshObject(descriptor, materialPalette, isSelected) {
 98→  const positions = [];
 99→
100→  function pushVertex(point, elevation) {
101→    positions.push(point.x, elevation, point.y);
102→  }
103→
104→  function pushTriangle(a, b, c, surface) {
105→    pushVertex(a, surface === 'top' ? a.topElevation : a.bottomElevation);
106→    pushVertex(b, surface === 'top' ? b.topElevation : b.bottomElevation);
107→    pushVertex(c, surface === 'top' ? c.topElevation : c.bottomElevation);
108→  }
109→
110→  function pushQuad(a, b) {
111→    pushVertex(a, a.topElevation);
112→    pushVertex(b, b.topElevation);
113→    pushVertex(b, b.bottomElevation);
114→
115→    pushVertex(a, a.topElevation);
116→    pushVertex(b, b.bottomElevation);
117→    pushVertex(a, a.bottomElevation);
118→  }
119→
120→  for (const surface of descriptor.surfaces || []) {
121→    const outline = surface.outline || [];
122→    if (outline.length < 3) continue;
123→
124→    const contour = outline.map((point) => new THREE.Vector2(point.x, -point.y));
125→    const faces = THREE.ShapeUtils.triangulateShape(contour, []);
126→
127→    for (const face of faces) {
128→      const a = outline[face[0]];
129→      const b = outline[face[1]];
130→      const c = outline[face[2]];
131→      pushTriangle(a, b, c, 'top');
132→      pushTriangle(c, b, a, 'bottom');
133→    }
134→  }
135→
136→  const outerBoundary = descriptor.outerBoundary || [];
137→  for (let index = 0; index < outerBoundary.length; index += 1) {
138→    const start = outerBoundary[index];
139→    const end = outerBoundary[(index + 1) % outerBoundary.length];
140→    pushQuad(start, end);
141→  }
142→
143→  const geometry = new THREE.BufferGeometry();
144→  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
145→  geometry.computeVertexNormals();
146→
147→  const mesh = new THREE.Mesh(geometry, createMeshMaterial(materialPalette, descriptor.materialKey, isSelected));
148→  mesh.castShadow = true;
149→  mesh.receiveShadow = true;
150→  addOutline(mesh, materialPalette, isSelected);
151→  return mesh;
152→}
153→
154→function createBoxObject(descriptor, materialPalette, isSelected) {
155→  const geometry = new THREE.BoxGeometry(
156→    Math.max(descriptor.size.x, 1),
157→    Math.max(descriptor.size.y, 1),
158→    Math.max(descriptor.size.z, 1)
159→  );
160→  const mesh = new THREE.Mesh(geometry, createMeshMaterial(materialPalette, descriptor.materialKey, isSelected));
161→  const center = planPointToWorld(
162→    descriptor.center,
163→    descriptor.baseElevation + descriptor.size.y / 2
164→  );
165→  mesh.position.copy(center);
166→  mesh.rotation.y = planAngleToWorldRotation(descriptor.rotation);
167→  mesh.castShadow = true;
168→  mesh.receiveShadow = true;
169→  addOutline(mesh, materialPalette, isSelected);
170→  return mesh;
171→}
172→
173→function createStairObject(descriptor, materialPalette, isSelected) {
174→  const group = new THREE.Group();
175→  const risers = Math.max(1, descriptor.numberOfRisers || 1);
176→
177→  for (let index = 0; index < risers; index += 1) {
178→    const geometry = new THREE.BoxGeometry(
179→      Math.max(descriptor.treadDepth, 1),
180→      Math.max(descriptor.riserHeight, 1),
181→      Math.max(descriptor.width, 1)
182→    );
183→    const step = new THREE.Mesh(geometry, createMeshMaterial(materialPalette, descriptor.materialKey, isSelected));
184→    step.position.set(
185→      descriptor.treadDepth * (index + 0.5),
186→      descriptor.riserHeight * (index + 0.5),
187→      0
188→    );
189→    step.castShadow = true;
190→    step.receiveShadow = true;
191→    addOutline(step, materialPalette, isSelected);
192→    group.add(step);
193→  }
194→
195→  group.position.copy(planPointToWorld(descriptor.startPoint, descriptor.baseElevation));
196→  group.rotation.y = planAngleToWorldRotation(descriptor.angle * Math.PI / 180);
197→  return group;
198→}
199→
200→function createSegment3DObject(descriptor, materialPalette, isSelected) {
201→  const start = new THREE.Vector3(descriptor.start.x, descriptor.start.y, descriptor.start.z);
202→  const end = new THREE.Vector3(descriptor.end.x, descriptor.end.y, descriptor.end.z);
203→  const direction = new THREE.Vector3().subVectors(end, start);
204→  const length = Math.max(direction.length(), 1);
205→  const crossSectionHeight = Math.max(descriptor.crossSection?.height || descriptor.thickness || 1, 1);
206→  const crossSectionWidth = Math.max(descriptor.crossSection?.width || descriptor.thickness || 1, 1);
207→  const geometry = new THREE.BoxGeometry(
208→    length,
209→    crossSectionHeight,
210→    crossSectionWidth
211→  );
212→  const mesh = new THREE.Mesh(geometry, createMeshMaterial(materialPalette, descriptor.materialKey, isSelected));
213→  const midpoint = new THREE.Vector3().addVectors(start, end).multiplyScalar(0.5);
214→  const quaternion = new THREE.Quaternion().setFromUnitVectors(
215→    new THREE.Vector3(1, 0, 0),
216→    direction.clone().normalize()
217→  );
218→
219→  mesh.position.copy(midpoint);
220→  mesh.quaternion.copy(quaternion);
221→  mesh.castShadow = true;
222→  mesh.receiveShadow = true;
223→  addOutline(mesh, materialPalette, isSelected);
224→  return mesh;
225→}
226→
227→function createWindowObject(descriptor, materialPalette, isSelected) {
228→  const group = new THREE.Group();
229→  const { x: width, y: height, z: depth } = descriptor.size;
230→
231→  const frameWidth = Math.max(40, Math.min(width, height) * 0.06);
232→  const glassThickness = Math.max(depth * 0.15, 10);
233→  const mullionWidth = frameWidth * 0.5;
234→
235→  const frameMaterial = createMeshMaterial(materialPalette, 'windowFrame', isSelected);
236→  const glassMaterial = createMeshMaterial(materialPalette, 'window', isSelected);
237→
238→  // Frame rails
239→  const frameRails = [
240→    // top
241→    { sx: width, sy: frameWidth, sz: depth, px: 0, py: (height - frameWidth) / 2, pz: 0 },
242→    // bottom
243→    { sx: width, sy: frameWidth, sz: depth, px: 0, py: -(height - frameWidth) / 2, pz: 0 },
244→    // left
245→    { sx: frameWidth, sy: height - frameWidth * 2, sz: depth, px: -(width - frameWidth) / 2, py: 0, pz: 0 },
246→    // right
247→    { sx: frameWidth, sy: height - frameWidth * 2, sz: depth, px: (width - frameWidth) / 2, py: 0, pz: 0 },
248→  ];
249→
250→  for (const rail of frameRails) {
251→    const geo = new THREE.BoxGeometry(
252→      Math.max(rail.sx, 1), Math.max(rail.sy, 1), Math.max(rail.sz, 1)
253→    );
254→    const mesh = new THREE.Mesh(geo, frameMaterial);
255→    mesh.position.set(rail.px, rail.py, rail.pz);
256→    mesh.castShadow = true;
257→    mesh.receiveShadow = true;
258→    addOutline(mesh, materialPalette, isSelected);
259→    group.add(mesh);
260→  }
261→
262→  // Glass pane (no outline — dark edges look wrong on glass)
263→  const innerW = width - frameWidth * 2;
264→  const innerH = height - frameWidth * 2;
265→  const glassGeo = new THREE.BoxGeometry(
266→    Math.max(innerW, 1), Math.max(innerH, 1), Math.max(glassThickness, 1)
267→  );
268→  const glassMesh = new THREE.Mesh(glassGeo, glassMaterial);
269→  glassMesh.castShadow = false;
270→  glassMesh.receiveShadow = true;
271→  group.add(glassMesh);
272→
273→  // Type-specific mullions
274→  const windowType = descriptor.windowType || 'standard';
275→  const mullions = [];
276→
277→  if (windowType === 'standard') {
278→    // 2 horizontal bars at 1/3 and 2/3 height
279→    const thirdH = innerH / 3;
280→    mullions.push(
281→      { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: -thirdH / 2 + innerH / 6, pz: 0 },
282→    );
283→    mullions.push(
284→      { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: thirdH / 2 - innerH / 6, pz: 0 },
285→    );
286→    // Positions: at -innerH/6 and +innerH/6 from center = 1/3 and 2/3 of inner height
287→    mullions.length = 0; // clear and redo cleanly
288→    mullions.push(
289→      { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: -innerH / 2 + innerH / 3, pz: 0 },
290→      { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: -innerH / 2 + (innerH * 2) / 3, pz: 0 },
291→    );
292→  } else if (windowType === 'casement') {
293→    // 1 vertical center bar
294→    mullions.push(
295→      { sx: mullionWidth, sy: innerH, sz: depth, px: 0, py: 0, pz: 0 },
296→    );
297→  } else if (windowType === 'awning') {
298→    // 1 horizontal bar at ~30% from top
299→    mullions.push(
300→      { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: innerH / 2 - innerH * 0.3, pz: 0 },
301→    );
302→  } else if (windowType === 'jalousie') {
303→    // 5 evenly-spaced horizontal bars
304→    for (let i = 1; i <= 5; i++) {
305→      const y = -innerH / 2 + (innerH * i) / 6;
306→      mullions.push(
307→        { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: y, pz: 0 },
308→      );
309→    }
310→  }
311→  // 'fixed' — no mullions
312→
313→  for (const m of mullions) {
314→    const geo = new THREE.BoxGeometry(
315→      Math.max(m.sx, 1), Math.max(m.sy, 1), Math.max(m.sz, 1)
316→    );
317→    const mesh = new THREE.Mesh(geo, frameMaterial);
318→    mesh.position.set(m.px, m.py, m.pz);
319→    mesh.castShadow = true;
320→    mesh.receiveShadow = true;
321→    addOutline(mesh, materialPalette, isSelected);
322→    group.add(mesh);
323→  }
324→
325→  // Position and rotate the group
326→  const center = planPointToWorld(
327→    descriptor.center,
328→    descriptor.baseElevation + height / 2
329→  );
330→  group.position.copy(center);
331→  group.rotation.y = planAngleToWorldRotation(descriptor.rotation);
332→
333→  return group;
334→}
