 36→export function clampWallOpeningOffset(length, width, offset) {
 37→  const safeLength = Math.max(0, Number(length) || 0);
 38→  const safeWidth = Math.max(0, Number(width) || 0);
 39→  const safeOffset = Number(offset) || 0;
 40→  const halfWidth = safeWidth / 2;
 41→
 42→  if (safeLength <= 0) return 0;
 43→  if (safeWidth >= safeLength) return safeLength / 2;
 44→
 45→  return Math.max(halfWidth, Math.min(safeLength - halfWidth, safeOffset));
